-- ============================================================================
-- Module Formation DDA — Phase 1 : import des programmes + assignation Émilie
--   - Contenu importé mécaniquement depuis :
--       DDA/S@FE-Formation-DDA-Contenu-2x7h30.md (programme générique)
--       Emilie_Formations/Emilie-DDA-Programme-Individualise.md (programme individualisé)
--   - Les 20 questions d'évaluation finale de chaque module ne sont pas
--     rédigées dans les documents source (seule leur description l'est) :
--     le champ `questions` des sections kind='evaluation' est donc vide,
--     à compléter en Phase 2/3 avant mise en production du QCM final.
--   - Pas de dda_sessions créée ici : aucune session de formation n'a
--     encore été dispensée/déclarée, ce sera fait via l'espace formateur
--     (Phase 3) ou lors du premier heartbeat e-learning (Phase 2).
--   - Sébastien (id 0ab219bd-92c9-4007-a50e-472ebbbf2132) est désigné
--     formateur interne (is_formateur = true).
--   - Émilie : pas de prorata sur 2026 (confirmé par l'utilisateur — seul
--     S@FE est immatriculé ORIAS, pas les collaborateurs individuellement ;
--     elle n'est pas dans sa première année d'exercice) => 15h pleines.
-- ============================================================================

update profiles set is_formateur = true
where id = '0ab219bd-92c9-4007-a50e-472ebbbf2132';

insert into dda_programmes (nom, perimetre_cible, contenu)
values (
  'Programme générique 2×7h30',
  '{}',
  $json${"sections": [{"id": "1_1", "module": "1", "kind": "lesson", "tab": "1.1 — Panorama et acteurs du marché de l'assurance", "title": "Panorama et acteurs du marché de l'assurance", "duree_minimale_min": 2, "contenu": ["Les grandes familles d'acteurs : entreprises d'assurance (porteurs de risque), courtiers grossistes (Dattak, Acheel, AMI3F, Hiscox — nos partenaires), courtiers de proximité (S@FE Assurances), agents généraux, mandataires.", "Rôle de S@FE : courtier immatriculé ORIAS (n°26008336), sans portage de risque, agissant dans l'intérêt du client (indépendance vis-à-vis des assureurs).", "Instances de régulation : ACPR (contrôle prudentiel et pratiques commerciales), ORIAS (registre unique des intermédiaires), CNIL (protection des données), France Assureurs (fédération professionnelle).", "Chiffres clés du marché français (poids économique, nombre d'intermédiaires, évolution digitale/assurtechs) — à actualiser annuellement via les publications France Assureurs."], "qcm_formatif": [{"q": "Qui tient le registre unique des intermédiaires en assurance ?", "reponse": "ORIAS."}, {"q": "S@FE Assurances porte-t-il le risque des contrats qu'il distribue ?", "reponse": "Non, ce sont les assureurs partenaires."}], "objectif": "situer S@FE Assurances dans la chaîne de valeur (assureur → grossiste → courtier → client) et identifier les instances de contrôle."}, {"id": "1_2", "module": "1", "kind": "lesson", "tab": "1.2 — Statuts d'intermédiaire, ORIAS, capacité, honorabilité", "title": "Statuts d'intermédiaire, ORIAS, capacité, honorabilité", "duree_minimale_min": 2, "contenu": ["Les 3 niveaux IAS (Art. R.512-9 à R.512-11 Code des assurances) : Niveau 1 (150h, courtiers/dirigeants), Niveau 2 (mandataires), Niveau 3 (distribution accessoire).", "Conditions cumulatives d'immatriculation ORIAS : capacité professionnelle + honorabilité (casier judiciaire, bulletin n°2) + garantie financière ou absence d'encaissement de fonds + assurance RC Professionnelle.", "Renouvellement annuel de l'immatriculation ORIAS (avant le 1er mars).", "La responsabilité du dirigeant : pour les salariés en contact avec la clientèle, l'employeur doit s'assurer de leur capacité et de leur honorabilité — pas seulement de la sienne.", "Cas S@FE : cumul Président/DPO — point de vigilance Art. 38§6 RGPD nécessitant des mesures compensatoires documentées (voir module RGPD)."], "qcm_formatif": [{"q": "Un salarié qui établit des devis pour des clients doit-il être personnellement immatriculé à l'ORIAS ?", "reponse": "Non, mais il doit justifier capacité professionnelle et honorabilité, et suivre la formation continue."}], "objectif": "comprendre les conditions d'accès et de maintien du statut d'intermédiaire."}, {"id": "1_3", "module": "1", "kind": "lesson", "tab": "1.3 — Le devoir de conseil : cœur de la DDA", "title": "Le devoir de conseil : cœur de la DDA", "duree_minimale_min": 2, "contenu": ["Textes fondateurs : Art. L.521-2 (recueil des exigences et besoins), L.521-4 (agir au mieux des intérêts du client), R.521-4 Code des assurances.", "Les 3 niveaux de conseil définis par l'ACPR :", "Niveau 1 (obligatoire) : proposer un contrat cohérent avec les besoins exprimés.", "Niveau 2 : recommandation personnalisée motivée.", "Niveau 3 : conseil sur la base d'une analyse objective d'un nombre suffisant de contrats du marché.", "Recommandation ACPR 2024-R-03 (21/11/2024) : précisions sur le recueil d'informations et la formalisation de la recommandation.", "La fiche de conseil : contenu obligatoire, traçabilité, conservation (5 ans glissants — Art. R.514-1), horodatage.", "Cas pratique S@FE : rattachement de la fiche de conseil au `prospect_id` dans SafeCRM avant toute redirection partenaire (cf. module commercial pour le lien avec le tunnel de prospection).", "Distinction perception de commission vs honoraires — obligation de déclarer la **nature** de la rémunération (pas nécessairement le montant, sauf demande expresse du client)."], "qcm_formatif": [{"q": "Le devoir de conseil s'arrête-t-il une fois le contrat souscrit ?", "reponse": "Non, il perdure sur toute la vie du contrat (avenants, renouvellements)."}, {"q": "Que doit contenir a minima le niveau 1 de conseil ?", "reponse": "Un contrat cohérent avec les besoins et exigences exprimés par le client."}], "objectif": "maîtriser les obligations de recueil de besoin et de conseil personnalisé, du premier contact à la signature."}, {"id": "1_4", "module": "1", "kind": "lesson", "tab": "1.4 — Documents normalisés : IPID, DIC, FSI", "title": "Documents normalisés : IPID, DIC, FSI", "duree_minimale_min": 2, "contenu": ["IPID (Insurance Product Information Document) : produits non-vie (auto, habitation, PNO, santé animale, cyber…) — format standardisé européen, remis avant souscription.", "DIC (Document d'Informations Clés) : produits d'investissement (assurance-vie, PER) — obligation renforcée d'information sur les frais et risques.", "FSI (Fiche Standardisée d'Information) : contexte spécifique de certains produits de crédit/assurance associée.", "Moment de remise : avant la conclusion du contrat, sur support durable (papier ou électronique tracé).", "Point d'attention SafeCRM : génération automatique et horodatée du bon document selon le `product_code` sélectionné dans le tunnel."], "qcm_formatif": [{"q": "Quel document remet-on pour un contrat auto ?", "reponse": "IPID."}], "objectif": "savoir quel document remettre selon le type de produit."}, {"id": "1_5", "module": "1", "kind": "lesson", "tab": "1.5 — Droit des contrats et pratiques commerciales", "title": "Droit des contrats et pratiques commerciales", "duree_minimale_min": 2, "contenu": ["Formation du contrat d'assurance : offre, acceptation, prise d'effet, délai de renonciation (Art. L.112-9, L.132-5-1 vie).", "Résiliation infra-annuelle (loi Hamon) : conditions, délais, produits concernés (auto, habitation, affinitaires).", "Démarchage téléphonique et vente à distance : information précontractuelle obligatoire, droit de rétractation (14 jours), enregistrement de l'accord du client.", "**Loi n°2025-594** (entrée en vigueur 11/08/2026) : opt-in explicite obligatoire pour le démarchage téléphonique des particuliers — sans impact sur la prospection B2B. Conséquence directe sur la piste d'audit consentement dans le module cold prospecting de SafeCRM.", "Charte de déontologie du courtage : loyauté, transparence, absence de conflit d'intérêts non déclaré."], "qcm_formatif": [{"q": "La loi n°2025-594 change-t-elle les règles de prospection B2B ?", "reponse": "Non, elle concerne le démarchage des particuliers."}], "objectif": "connaître le cadre légal de la formation du contrat et des pratiques de vente à distance / démarchage."}, {"id": "1_6", "module": "1", "kind": "lesson", "tab": "1.6 — LCB-FT : lutte contre le blanchiment et le financement du terrorisme", "title": "LCB-FT : lutte contre le blanchiment et le financement du terrorisme", "duree_minimale_min": 2, "contenu": ["Cadre : Code monétaire et financier, obligations Tracfin, analyse nationale des risques LCB-FT.", "Vigilance à l'entrée en relation : identification du client, du bénéficiaire effectif.", "Vigilance renforcée : personnes politiquement exposées (PPE), pays à risque, montages inhabituels.", "Déclaration de soupçon Tracfin : quand et comment, obligation de confidentialité (interdiction d'en informer le client).", "Application pratique chez S@FE : produits concernés principalement épargne/vie ; vigilance standard pour l'IARD."], "qcm_formatif": [{"q": "Peut-on informer un client qu'une déclaration de soupçon a été faite à son sujet ?", "reponse": "Non, c'est interdit par la loi."}], "objectif": "appliquer les obligations de vigilance sur les contrats d'assurance-vie et d'épargne notamment."}, {"id": "1_7", "module": "1", "kind": "lesson", "tab": "1.7 — RGPD appliqué à la distribution d'assurance", "title": "RGPD appliqué à la distribution d'assurance", "duree_minimale_min": 2, "contenu": ["Rappel des bases légales applicables : exécution du contrat, obligation légale, intérêt légitime (prospection B2B), consentement (prospection particuliers).", "Données sensibles en assurance : santé (complémentaire santé, prévoyance), et leur régime renforcé (Art. 9 RGPD).", "Durées de conservation différenciées : prospects non convertis (3 ans), clients (durée du contrat + prescription), documents comptables (10 ans).", "Droits des personnes appliqués au parcours client : information dès la collecte (mentions RGPD sur le tunnel de prospection), droit d'accès, droit à l'effacement (limites liées aux obligations légales de conservation).", "Sécurité : chiffrement, cloisonnement `establishments` (public) vs `prospects` (consentement + audit), traçabilité des accès.", "DPA fournisseurs : Stripe (automatique via SSA), Supabase (signé), en attente pour Brevo/Anthropic/xAI — illustre l'exigence de cartographie des sous-traitants.", "Cas du cumul Président/DPO : nécessité de mesures compensatoires documentées (séparation des tâches, reporting, comité indépendant le cas échéant)."], "qcm_formatif": [{"q": "Sur quelle base légale repose la prospection B2B (établissements) sans consentement préalable ?", "reponse": "L'intérêt légitime, sous réserve d'information et de droit d'opposition."}], "objectif": "relier les obligations RGPD génériques aux spécificités du courtage (données sensibles, souscription, sinistres)."}, {"id": "1_8", "module": "1", "kind": "lesson", "tab": "1.8 — Vie du contrat, réclamations et médiation", "title": "Vie du contrat, réclamations et médiation", "duree_minimale_min": 2, "contenu": ["Suivi de la vie du contrat : avenants, changements de risque, ré-analyse du devoir de conseil à chaque modification substantielle.", "Traitement des réclamations : délai d'accusé de réception (10 jours ouvrables), délai de réponse (2 mois), traçabilité obligatoire.", "La médiation de l'assurance : conditions de saisine (réclamation préalable épuisée), gratuité pour le client, caractère consultatif de l'avis du médiateur.", "Relation client à distance : bonnes pratiques (canaux, traçabilité des échanges, ton et posture).", "Recommandation ACPR sur le traitement des réclamations : formalisme attendu, indicateurs de suivi."], "qcm_formatif": [{"q": "Le client peut-il saisir directement le médiateur sans réclamation préalable ?", "reponse": "Non, la réclamation auprès du professionnel est un préalable obligatoire."}], "objectif": "sécuriser la relation client après la souscription."}, {"id": "1_9", "module": "1", "kind": "lesson", "tab": "1.9 — Gouvernance, formation continue, cumul de fonctions", "title": "Gouvernance, formation continue, cumul de fonctions", "duree_minimale_min": 2, "contenu": ["Gouvernance produit DDA : conception, validation, marché cible, suivi post-commercialisation des produits distribués.", "Obligation de formation continue 15h/an : qui, quoi, comment tracer (rappel synthétique — table `dda_obligations` / `dda_sessions` dans SafeCRM).", "Sanctions ACPR en cas de manquement : de l'avertissement au retrait d'immatriculation ORIAS.", "Traçabilité documentaire globale : où sont archivées les fiches de conseil, attestations de formation, DPA, conventions de partenariat — cohérence avec la politique documentaire S@FE."], "qcm_formatif": [{"q": "Quelle est la durée de conservation des justificatifs de formation continue ?", "reponse": "5 ans glissants."}], "objectif": "boucler sur les obligations de pilotage interne de la conformité."}, {"id": "evaluation_1", "module": "1", "kind": "evaluation", "tab": "Évaluation finale Module 1", "title": "Évaluation finale Module 1", "duree_minimale_min": 2, "description": "20 questions QCM couvrant les 9 unités, seuil de validation 70%, génération d'une attestation de suivi (module interne, cf. mise en garde en préambule).", "questions": []}, {"id": "2_1", "module": "2", "kind": "lesson", "tab": "2.1 — Posture du conseiller et techniques générales de vente", "title": "Posture du conseiller et techniques générales de vente", "duree_minimale_min": 2, "contenu": ["Différence entre vendre un produit et conseiller une couverture : la vente en assurance est indissociable du devoir de conseil (cf. Module 1).", "Les qualités attendues du vendeur-négociateur : écoute active, rigueur, pédagogie, patience face à un produit perçu comme abstrait.", "La confiance comme levier commercial : transparence sur la rémunération, honnêteté sur les limites de garanties."], "qcm_formatif": [{"q": "Le conseil commercial en assurance peut-il être dissocié du devoir de conseil réglementaire ?", "reponse": "Non, ils sont indissociables."}], "objectif": "poser les fondamentaux comportementaux du conseil commercial en assurance."}, {"id": "2_2", "module": "2", "kind": "lesson", "tab": "2.2 — Communication non verbale et comportement", "title": "Communication non verbale et comportement", "duree_minimale_min": 2, "contenu": ["Indicateurs de communication non verbale : posture, ton de voix, débit, silences — leur poids même en distanciel (visio) ou au téléphone (paralangage).", "Les atouts du bon négociateur : calme, capacité à reformuler, gestion des tensions sans céder sur les intérêts du client.", "Adapter sa posture au profil du client (particulier vs dirigeant de TPE/PME) et au canal (tunnel digital SafeCRM vs échange humain)."], "qcm_formatif": [], "objectif": "décoder et maîtriser les signaux non verbaux en entretien (présentiel, visio, téléphone)."}, {"id": "2_3", "module": "2", "kind": "lesson", "tab": "2.3 — Cadre légal du démarchage et de la vente à distance — application opérationnelle", "title": "Cadre légal du démarchage et de la vente à distance — application opérationnelle", "duree_minimale_min": 2, "contenu": ["Script d'ouverture d'appel conforme (mention de l'identité, de la société, du caractère commercial de l'appel).", "Gestion du consentement en amont d'une campagne de prospection téléphonique particuliers (anticipation loi n°2025-594).", "Ce qui est permis en B2B vs ce qui nécessite un accord explicite en B2C.", "Traçabilité de l'accord client dans SafeCRM (horodatage, canal, contenu exact du consentement)."], "qcm_formatif": [{"q": "Doit-on mentionner le caractère commercial de l'appel dès l'ouverture ?", "reponse": "Oui, c'est une obligation d'information précontractuelle."}], "objectif": "transformer les règles vues en Module 1 en réflexes opérationnels sur le terrain."}, {"id": "2_4", "module": "2", "kind": "lesson", "tab": "2.4 — La démarche commerciale : vue d'ensemble", "title": "La démarche commerciale : vue d'ensemble", "duree_minimale_min": 2, "contenu": ["Les étapes classiques : prise de contact → découverte → présentation de l'offre → traitement des objections → conclusion → suivi.", "Spécificité S@FE : le tunnel peut s'arrêter avant la signature (redirection partenaire ou ressaisie manuelle) — la démarche commerciale doit donc intégrer ce point de bascule comme une étape à part entière, pas comme un abandon.", "Notion de cycle de vente long (professionnels, risques complexes) vs court (particuliers, produits standards type PNO ou santé animale)."], "qcm_formatif": [], "objectif": "cartographier les grandes étapes d'un cycle de vente en assurance."}, {"id": "2_5", "module": "2", "kind": "lesson", "tab": "2.5 — Préparation et découverte client", "title": "Préparation et découverte client", "duree_minimale_min": 2, "contenu": ["Checklist de préparation avant tout entretien : connaissance du profil (SIRET auto-complété, historique CRM, produits déjà détenus).", "Techniques de questionnement : questions ouvertes (exploration des besoins), questions fermées (validation), questions de reformulation.", "Recueil structuré des besoins et exigences — alimente directement la fiche de conseil DDA (lien direct avec Module 1, Unité 1.3).", "Identifier les signaux d'un besoin non exprimé (ex. un professionnel évoquant une cyberattaque récente chez un confrère → opportunité cyber + RCP)."], "qcm_formatif": [{"q": "Une question fermée sert principalement à…", "reponse": "Valider une information déjà évoquée."}], "objectif": "maîtriser le questionnement qui alimente à la fois la vente et le devoir de conseil réglementaire."}, {"id": "2_6", "module": "2", "kind": "lesson", "tab": "2.6 — Présentation de l'offre et méthode AIDA", "title": "Présentation de l'offre et méthode AIDA", "duree_minimale_min": 2, "contenu": ["Méthode AIDA (Attention, Intérêt, Désir, Action) appliquée à un produit d'assurance : exemple concret sur une offre Cyber + RCP pour une TPE.", "Présenter les garanties ET les exclusions — la transparence sur les exclusions fait partie du devoir de conseil, pas seulement de l'éthique commerciale.", "Argumentaire structuré caractéristique → avantage → bénéfice client, avec supports (IPID, comparatif garanties) remis en simultané.", "Lien avec la remise des documents normalisés (Module 1, Unité 1.4) : présenter n'est pas informer légalement — les deux sont nécessaires."], "qcm_formatif": [{"q": "Présenter oralement les garanties dispense-t-il de remettre l'IPID ?", "reponse": "Non, la remise du document normalisé reste obligatoire."}], "objectif": "structurer une présentation d'offre efficace et conforme."}, {"id": "2_7", "module": "2", "kind": "lesson", "tab": "2.7 — Traitement des objections", "title": "Traitement des objections", "duree_minimale_min": 2, "contenu": ["Typologie des objections fréquentes en assurance : prix, méfiance envers les intermédiaires, \"j'ai déjà une assurance\", \"je vais réfléchir\", complexité perçue du produit (cyber, RC Pro).", "Méthode de traitement : accueillir l'objection → reformuler → répondre avec un fait ou une preuve → valider que l'objection est levée.", "Technique d'instauration du doute maîtrisée (ex. sur une couverture insuffisante ou obsolète) — à utiliser avec rigueur factuelle, jamais par exagération du risque (limite déontologique claire, cf. charte de déontologie Module 1).", "Objections spécifiques au modèle S@FE : \"pourquoi je finis sur un autre site pour signer ?\" → argumentaire transparent sur le rôle de conseil vs le rôle de porteur de risque."], "qcm_formatif": [{"q": "La technique d'instauration du doute doit-elle s'appuyer sur des faits vérifiables ?", "reponse": "Oui, toute exagération du risque est une pratique commerciale déloyale."}], "objectif": "répondre aux objections courantes sans dériver vers des pratiques commerciales déloyales."}, {"id": "2_8", "module": "2", "kind": "lesson", "tab": "2.8 — Reformulation et conclusion de la vente", "title": "Reformulation et conclusion de la vente", "duree_minimale_min": 2, "contenu": ["Techniques de reformulation : résumer les besoins et la solution retenue avant de conclure, pour vérifier l'adhésion du client et sécuriser la traçabilité du conseil donné.", "Signaux d'achat à repérer, techniques de conclusion (sans forcer, dans le respect de l'intérêt du client).", "Cas S@FE spécifique : conclure un entretien qui débouche sur une redirection (Wakam-like tracké) vs une ressaisie manuelle (type Acheel/Hermès) — le discours de conclusion doit différer selon le cas, en étant transparent sur les prochaines étapes pour le client."], "qcm_formatif": [], "objectif": "sécuriser la fin de l'entretien, qu'il aboutisse à une signature immédiate ou à une redirection partenaire."}, {"id": "2_9", "module": "2", "kind": "lesson", "tab": "2.9 — Démarchage téléphonique : script, négociation, finalisation", "title": "Démarchage téléphonique : script, négociation, finalisation", "duree_minimale_min": 2, "contenu": ["Mener une campagne d'appels sortants : ciblage, cadence, respect des créneaux légaux, qualité de la liste (établissements vs prospects avec consentement).", "Construction du script d'appel : accroche, qualification, transition vers la découverte, sans réciter un texte de façon mécanique.", "Négocier au téléphone : gérer l'absence de langage corporel, s'appuyer sur le ton, le silence, la reformulation.", "Finaliser l'appel : engager un prochain pas concret (rendez-vous, envoi de devis, redirection partenaire), consigner l'issue dans le CRM avec le statut adéquat (`redirected_to_partner`, `pending_manual_entry`, `a_recontacter`…)."], "qcm_formatif": [{"q": "Un script d'appel doit-il être récité mot pour mot ?", "reponse": "Non, c'est un guide, l'adaptation à l'interlocuteur reste essentielle."}], "objectif": "professionnaliser la pratique de l'appel sortant, du script à la clôture."}, {"id": "evaluation_2", "module": "2", "kind": "evaluation", "tab": "Évaluation finale Module 2", "title": "Évaluation finale Module 2", "duree_minimale_min": 2, "description": "20 questions QCM couvrant les 9 unités, seuil de validation 70%, génération d'une attestation de suivi.", "questions": []}]}$json$::jsonb
);

insert into dda_programmes (nom, perimetre_cible, contenu)
values (
  'Programme individualisé — Émilie Culat (Professionnels)',
  '{professionnels}',
  $json${"sections": [{"id": "a_1", "module": "A", "kind": "lesson", "tab": "A.1 — Panorama du marché et rôle de S@FE", "title": "Panorama du marché et rôle de S@FE", "duree_minimale_min": 2, "contenu": ["Chaîne de valeur : assureurs porteurs de risque pro (Hiscox notamment) → grossistes/insurtechs (Dattak, AMI3F) → S@FE Assurances (courtier, ORIAS n°26008336).", "Spécificité du marché des risques professionnels : cycle de vente plus long, analyse de risque plus fine (secteur d'activité, effectif, chiffre d'affaires), acteurs interlocuteurs différents (dirigeant, DAF, parfois RSSI pour le cyber)."], "qcm_formatif": [{"q": "S@FE porte-t-il le risque des contrats Cyber+RCP ou RC Décennale qu'il distribue ?", "reponse": "Non, ce sont les assureurs partenaires (Hiscox, Dattak…)."}]}, {"id": "a_2", "module": "A", "kind": "lesson", "tab": "A.2 — Statuts d'intermédiaire, capacité, honorabilité", "title": "Statuts d'intermédiaire, capacité, honorabilité", "duree_minimale_min": 2, "contenu": ["Rappel des 3 niveaux IAS et de la responsabilité du dirigeant (Sébastien) concernant la capacité et l'honorabilité de ses collaborateurs en contact clientèle — cas direct d'Émilie.", "Renouvellement ORIAS annuel (avant le 1er mars), et lien avec la présente obligation de formation continue individualisée."], "qcm_formatif": []}, {"id": "a_3", "module": "A", "kind": "lesson", "tab": "A.3 — Le devoir de conseil appliqué aux risques professionnels", "title": "Le devoir de conseil appliqué aux risques professionnels", "duree_minimale_min": 2, "contenu": ["Rappel des textes (Art. L.521-2, L.521-4, R.521-4) et des 3 niveaux de conseil ACPR, appliqués spécifiquement au contexte pro.", "**Spécificité de l'analyse de besoin en risque professionnel** : au-delà des exigences du client, le conseil doit intégrer une analyse objective du profil de risque de l'entreprise — secteur d'activité (code NAF), effectif, chiffre d'affaires, antériorité de sinistralité, exposition spécifique (ex. un e-commerçant vs un cabinet de conseil pour le Cyber ; une entreprise du BTP pour la RC Décennale).", "Recommandation ACPR 2024-R-03 : application au recueil d'informations pour des risques complexes (professionnels), plus exigeant qu'un devis particulier standardisé.", "La fiche de conseil pour un risque professionnel : contenu spécifique attendu (justification du choix de garanties au regard du profil d'activité, mention explicite des exclusions pertinentes pour ce secteur).", "Cas pratique : construire une fiche de conseil pour une TPE e-commerce (Cyber) vs une entreprise du BTP (RC Décennale) — les éléments de justification diffèrent totalement."], "qcm_formatif": [{"q": "Pour un risque Cyber, quel élément du profil client est central dans l'analyse de besoin ?", "reponse": "La nature et le volume des données traitées, ainsi que la dépendance de l'activité aux systèmes numériques."}]}, {"id": "a_4", "module": "A", "kind": "lesson", "tab": "A.4 — Document normalisé : l'IPID en risques professionnels", "title": "Document normalisé : l'IPID en risques professionnels", "duree_minimale_min": 2, "contenu": ["Focus exclusif IPID (les produits distribués par Émilie sont tous IARD professionnels — pas de DIC, hors périmètre).", "Spécificités de lecture de l'IPID pour des garanties complexes (Cyber : distinction 1re ligne / 3e ligne de responsabilité ; RC Décennale : nature de la garantie obligatoire vs facultative).", "Moment et modalité de remise dans le tunnel SafeCRM (génération automatique liée au `product_code`)."], "qcm_formatif": []}, {"id": "a_5", "module": "A", "kind": "lesson", "tab": "A.5 — Droit des contrats et pratiques commerciales B2B", "title": "Droit des contrats et pratiques commerciales B2B", "duree_minimale_min": 2, "contenu": ["Formation du contrat, délais, spécificités des contrats professionnels (durée, tacite reconduction, préavis de résiliation souvent différents des contrats particuliers).", "Démarchage et prospection B2B : cadre légal actuel, non concerné par le futur opt-in de la loi n°2025-594 (réservée aux particuliers) — mais bonnes pratiques de traçabilité du consentement à conserver malgré tout dans SafeCRM (module `establishments`/`prospects`).", "Charte de déontologie : loyauté et transparence appliquées à des interlocuteurs professionnels (dirigeants, DAF) souvent plus avertis mais pas toujours sur les spécificités assurantielles."], "qcm_formatif": []}, {"id": "a_6", "module": "A", "kind": "lesson", "tab": "A.6 — LCB-FT dans le contexte des risques professionnels", "title": "LCB-FT dans le contexte des risques professionnels", "duree_minimale_min": 2, "contenu": ["Vigilance renforcée sur les structures complexes (holdings, sociétés à montages multiples) plus fréquentes en BTP (RC Décennale) ou en flotte (groupes multi-sites).", "Identification du bénéficiaire effectif pour une personne morale — procédure S@FE via SIRET auto-complété.", "Signaux d'alerte spécifiques aux professionnels (structure sans activité réelle apparente, incohérence effectif/CA/risque assuré)."], "qcm_formatif": []}, {"id": "a_7", "module": "A", "kind": "lesson", "tab": "A.7 — RGPD appliqué à la distribution de risques professionnels", "title": "RGPD appliqué à la distribution de risques professionnels", "duree_minimale_min": 2, "contenu": ["Spécificité : les clients d'Émilie sont eux-mêmes souvent responsables de traitement (le RGPD n'est pas qu'une contrainte interne S@FE, c'est aussi un sujet métier direct pour un client Cyber).", "Notification de sinistre Cyber et obligations RGPD du client assuré : lien entre déclaration de sinistre et obligation de notification CNIL sous 72h en cas de violation de données — Émilie doit savoir orienter le client sur ce point sans se substituer au conseil juridique.", "Traçabilité RGPD du tunnel de prospection B2B (`establishments` = données publiques, `prospects` = consentement et audit trail) — rappel opérationnel de ce qu'Émilie doit respecter au quotidien."], "qcm_formatif": [{"q": "Sous quel délai une entreprise victime d'une cyberattaque avec fuite de données doit-elle notifier la CNIL ?", "reponse": "72 heures."}]}, {"id": "a_8", "module": "A", "kind": "lesson", "tab": "A.8 — Vie du contrat, réclamations et médiation en risques professionnels", "title": "Vie du contrat, réclamations et médiation en risques professionnels", "duree_minimale_min": 2, "contenu": ["Spécificités de gestion de sinistre professionnel : délais de déclaration souvent plus courts et procédures plus strictes en Cyber (urgence de la réponse à incident) ; garantie décennale mobilisable jusqu'à 10 ans après réception des travaux (délai bien plus long que les sinistres classiques).", "Traitement des réclamations et médiation, appliqués à un contexte B2B (interlocuteurs différents, enjeux financiers souvent plus importants).", "Ré-analyse du devoir de conseil en cas d'évolution de l'activité du client (croissance de l'effectif, nouveau marché à l'export, changement d'activité) — déclenche une nouvelle analyse de risque, pas un simple avenant administratif."], "qcm_formatif": []}, {"id": "a_9", "module": "A", "kind": "lesson", "tab": "A.9 — Gouvernance et formation continue", "title": "Gouvernance et formation continue", "duree_minimale_min": 2, "contenu": ["Rappel du cadre de gouvernance produit DDA appliqué aux partenariats S@FE (conventions Dattak, AMI3F, Hiscox — devoir de conseil porté par S@FE, pas par l'assureur).", "Traçabilité de la présente formation continue individualisée : registre, attestation, conservation 5 ans."], "qcm_formatif": []}, {"id": "evaluation_a", "module": "A", "kind": "evaluation", "tab": "Évaluation Module A", "title": "Évaluation Module A", "duree_minimale_min": 2, "description": "20 questions QCM, seuil 70%, avec au moins 8 questions portant spécifiquement sur les cas pratiques professionnels (Cyber, RC Pro, RC Décennale, Flotte).", "questions": []}, {"id": "b_1", "module": "B", "kind": "lesson", "tab": "B.1 — Panorama des risques professionnels du catalogue S@FE", "title": "Panorama des risques professionnels du catalogue S@FE", "duree_minimale_min": 2, "contenu": ["Vue d'ensemble structurée des 4 familles : Cyber + RCP, RC Pro, RC Décennale, Flotte automobile professionnelle.", "Pour chaque famille : typologie de clients cibles, partenaire(s) porteur(s) (Dattak pour le cyber notamment), niveau de complexité du conseil requis.", "Positionnement de S@FE sur ces lignes : ce qui est standardisé (tunnel digital) vs ce qui nécessite un accompagnement humain approfondi (risques atypiques, montants élevés)."], "qcm_formatif": []}, {"id": "b_2", "module": "B", "kind": "lesson", "tab": "B.2 — Cyber assurance et RCP approfondis", "title": "Cyber assurance et RCP approfondis", "duree_minimale_min": 2, "contenu": ["Garanties type : frais de gestion de crise, pertes d'exploitation suite à cyberattaque, RC découlant d'une fuite de données, rançongiciel (selon contrat).", "Exclusions fréquentes à connaître et à expliquer clairement (ex. défaut de mise à jour de sécurité connue, actes de guerre cyber selon les contrats).", "Lien direct avec le RGPD (Module A.7) : le conseil sur ce produit est indissociable d'une explication des obligations légales du client assuré en cas de sinistre.", "Argumentaire adapté à un dirigeant de TPE/PME peu sensibilisé au risque cyber (statistiques sectorielles, exemples anonymisés de sinistres)."], "qcm_formatif": []}, {"id": "b_3", "module": "B", "kind": "lesson", "tab": "B.3 — RC Professionnelle et RC Décennale", "title": "RC Professionnelle et RC Décennale", "duree_minimale_min": 2, "contenu": ["RC Pro : risques couverts (erreur, omission, négligence dans l'exercice de l'activité), secteurs à obligation légale (professions réglementées) vs facultative.", "RC Décennale : cadre légal (Loi Spinetta de 1978), obligation pour les constructeurs, durée de la garantie (10 ans après réception), articulation avec l'assurance dommages-ouvrage.", "Différences clés à expliquer au client : une RC Pro standard ne couvre pas les dommages à l'ouvrage lui-même, contrairement à la décennale."], "qcm_formatif": [{"q": "Combien de temps après la réception des travaux la garantie décennale reste-t-elle mobilisable ?", "reponse": "10 ans."}]}, {"id": "b_4", "module": "B", "kind": "lesson", "tab": "B.4 — Flotte automobile professionnelle", "title": "Flotte automobile professionnelle", "duree_minimale_min": 2, "contenu": ["Spécificités par rapport à l'assurance auto particulier : désignation des conducteurs (flotte nominative) vs \"tous conducteurs\", gestion du bonus-malus au niveau de la flotte, véhicules de service vs véhicules de fonction/mission.", "Points de vigilance devoir de conseil : nombre de véhicules, profil des conducteurs, usage (marchandises, transport de personnes), zone géographique d'exploitation."], "qcm_formatif": []}, {"id": "b_5", "module": "B", "kind": "lesson", "tab": "B.5 — Prospection B2B et cadre RGPD spécifique", "title": "Prospection B2B et cadre RGPD spécifique", "duree_minimale_min": 2, "contenu": ["Rappel opérationnel de l'architecture SafeCRM : `establishments` (données publiques, sans consentement requis) vs `prospects` (consentement, audit trail, rétention 3 ans).", "Sources de prospection B2B légitimes (bases publiques, réseau, recommandations) et limites à respecter malgré l'absence d'opt-in obligatoire en B2B (loi n°2025-594 non applicable, mais bonne pratique de traçabilité).", "Qualification d'un prospect professionnel : secteur NAF, effectif, signaux d'exposition au risque (ex. actualité sectorielle sur les cyberattaques, chantier en cours pour la décennale)."], "qcm_formatif": []}, {"id": "b_6", "module": "B", "kind": "lesson", "tab": "B.6 — Découverte client et analyse de profil d'entreprise", "title": "Découverte client et analyse de profil d'entreprise", "duree_minimale_min": 2, "contenu": ["Techniques de questionnement adaptées à un interlocuteur professionnel (dirigeant, DAF) : moins de questions \"besoins personnels\", plus de questions \"exposition de l'activité\".", "Exploitation du SIRET auto-complété dans SafeCRM : quelles données il apporte (forme juridique, code NAF, ancienneté) et ce qu'il faut compléter à l'oral (effectif réel, CA, sinistralité passée, projets en cours).", "Grille de questionnement type par produit (Cyber : dépendance numérique, données traitées ; Décennale : nature des travaux, sous-traitance ; Flotte : usage et kilométrage)."], "qcm_formatif": []}, {"id": "b_7", "module": "B", "kind": "lesson", "tab": "B.7 — Présentation de l'offre et traitement des objections professionnelles", "title": "Présentation de l'offre et traitement des objections professionnelles", "duree_minimale_min": 2, "contenu": ["Méthode AIDA appliquée à un dirigeant d'entreprise : accroche sur un risque concret sectoriel, mise en perspective financière (coût d'un sinistre non couvert vs prime annuelle).", "Objections typiques en B2B : \"je n'ai jamais eu de sinistre\", \"mon assurance actuelle couvre déjà ça\" (souvent faux sur le cyber), \"c'est trop cher pour mon budget de TPE\", \"je n'ai pas le temps\".", "Traitement rigoureux, factuel, jamais alarmiste au-delà de la réalité du risque (limite déontologique rappelée en Module A.5)."], "qcm_formatif": []}, {"id": "b_8", "module": "B", "kind": "lesson", "tab": "B.8 — Conclusion et transmission vers le partenaire", "title": "Conclusion et transmission vers le partenaire", "duree_minimale_min": 2, "contenu": ["Rappel des deux parcours possibles selon le partenaire (cf. schéma SafeCRM) : redirection tracée automatique vs ressaisie manuelle (cas actuel Acheel/Hermès).", "Discours de conclusion adapté selon le cas : transparence totale sur la suite du parcours pour le client professionnel, qui peut être plus exigeant qu'un particulier sur la clarté du processus.", "Consignation du statut dans SafeCRM (`redirected_to_partner`, `pending_manual_entry`) et lien avec le suivi commercial (relance si non finalisé)."], "qcm_formatif": []}, {"id": "evaluation_b", "module": "B", "kind": "evaluation", "tab": "Évaluation Module B", "title": "Évaluation Module B", "duree_minimale_min": 2, "description": "20 questions QCM couvrant les 8 unités, avec mise en situation écrite (étude de cas : construire une fiche de conseil pour un client fictif TPE BTP demandant Décennale + Flotte).", "questions": []}]}$json$::jsonb
